import time
import random

def call_with_retry(fn, max_retries=3, base_delay=1.0):
    for attempt in range(max_retries):
        try:
            return fn()
        except RateLimitError:
            if attempt == max_retries - 1:
                raise
            delay = base_delay * (2 ** attempt) + random.uniform(0, 1)
            time.sleep(delay)
    raise RuntimeError('Max retries exceeded')

class CircuitBreaker:
    def __init__(self, failure_threshold=5, recovery_timeout=60):
        self.failure_count = 0
        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout
        self.state = 'closed'  # closed, open, half-open
        self.last_failure_time = None

    def call(self, fn, *args, **kwargs):
        if self.state == 'open':
            elapsed = time.time() - self.last_failure_time
            if elapsed > self.recovery_timeout:
                self.state = 'half-open'
            else:
                raise CircuitOpenError('Circuit breaker is open')

        try:
            result = fn(*args, **kwargs)
            self.on_success()
            return result
        except Exception as e:
            self.on_failure()
            raise

    def on_success(self):
        self.failure_count = 0
        self.state = 'closed'

    def on_failure(self):
        self.failure_count += 1
        self.last_failure_time = time.time()
        if self.failure_count >= self.failure_threshold:
            self.state = 'open'

from concurrent.futures import ThreadPoolExecutor
from threading import Semaphore

class BulkheadExecutor:
    def __init__(self, max_concurrent=10, queue_size=100):
        self.semaphore = Semaphore(max_concurrent)
        self.executor = ThreadPoolExecutor(max_workers=max_concurrent)

    def submit(self, fn, *args, **kwargs):
        if not self.semaphore.acquire(blocking=False):
            raise BulkheadFullError('Bulkhead capacity exceeded')
        try:
            future = self.executor.submit(fn, *args, **kwargs)
            future.add_done_callback(lambda f: self.semaphore.release())
            return future
        except Exception:
            self.semaphore.release()
            raise
